1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it.todo("two adjacent cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []");
12	  it("live cell with 2 neighbors survives (rule 2 - survival)", () => {
13	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
14	    expect(result).toContainEqual([1, 0]);
15	  });
16	  it("live cell with 3 neighbors survives (rule 2 - survival)", () => {
17	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
18	    expect(result).toContainEqual([0, 0]);
19	  });
20	  it("live cell with 4 neighbors dies (rule 3 - overpopulation)", () => {
21	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it("dead cell with exactly 3 neighbors becomes alive (rule 4 - reproduction) — [(0,0),(1,0),(0,1)] produces (1,1)", () => {
25	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
26	    expect(result).toContainEqual([1, 1]);
27	  });
28	  it("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
29	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
30	    const result = nextGeneration(block);
31	    expect(result.sort()).toEqual(block.sort());
32	  });
33	  it("blinker vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
34	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
35	    const sortKey = (c: Cell) => `${c[0]},${c[1]}`;
36	    expect(result.sort((a, b) => sortKey(a).localeCompare(sortKey(b))))
37	      .toEqual([[-1, 1], [0, 1], [1, 1]].sort((a, b) => sortKey(a as Cell).localeCompare(sortKey(b as Cell))));
38	  });
39	  it.todo("handles negative coordinates correctly");
40	});
